Step-by-step to add a new component, e.g. a `PatientRiskBadge` component:

**1. Create the component file**
```tsx
// therapeutic-copilot/client/src/components/PatientRiskBadge.tsx
interface Props {
  riskScore: number;  // 0.0 to 1.0
  patientName: string;
}

export function PatientRiskBadge({ riskScore, patientName }: Props) {
  const level = riskScore > 0.8 ? 'high' : riskScore > 0.5 ? 'medium' : 'low';
  const colors = { high: 'bg-red-100 text-red-800', medium: 'bg-yellow-100 text-yellow-800', low: 'bg-green-100 text-green-800' };

  return (
    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${colors[level]}`}>
      {patientName} — {level.toUpperCase()} RISK ({(riskScore * 100).toFixed(0)}%)
    </span>
  );
}
```

**2. Fetch data using TanStack Query**
```tsx
// In the parent component (e.g. ClinicianDashboard.tsx)
import { useQuery } from '@tanstack/react-query';
import { api } from '@/lib/api';
import { PatientRiskBadge } from '@/components/PatientRiskBadge';

const { data: patients } = useQuery({
  queryKey: ['patients'],
  queryFn: () => api.get('/api/v1/patients').then(r => r.data),
});

// In JSX:
{patients?.map(p => (
  <PatientRiskBadge key={p.id} riskScore={p.dropout_risk_score} patientName={p.full_name} />
))}
```

**3. The API call uses the Axios instance from `lib/api.ts`**
```tsx
// lib/api.ts automatically injects JWT from localStorage:
// Authorization: Bearer <token>
// You never need to manually add auth headers.
```

The WebSocket hook is in `client/src/hooks/useChat.ts`. Here's how it works and how to extend it:

```tsx
// hooks/useClinicianAlerts.ts — WebSocket for clinician crisis alerts
import { useEffect, useRef, useState } from 'react';
import { useAuthStore } from '@/stores/authStore';

interface CrisisAlert {
  type: 'CRISIS_ALERT';
  patient_id: string;
  patient_name: string;
  crisis_score: number;
  message_preview: string;
  timestamp: string;
}

export function useClinicianAlerts() {
  const [alerts, setAlerts] = useState<CrisisAlert[]>([]);
  const ws = useRef<WebSocket | null>(null);
  const clinicianId = useAuthStore(s => s.user?.id);

  useEffect(() => {
    if (!clinicianId) return;

    // Backend: ws_routes.py handles /ws/clinician/{id}
    ws.current = new WebSocket(`ws://localhost:8000/ws/clinician/${clinicianId}`);

    ws.current.onmessage = (event) => {
      const data = JSON.parse(event.data);
      if (data.type === 'CRISIS_ALERT') {
        setAlerts(prev => [data, ...prev]);
        // Play alert sound, show toast, etc.
      }
    };

    ws.current.onclose = () => {
      // Reconnect after 3 seconds
      setTimeout(() => ws.current?.close(), 3000);
    };

    return () => ws.current?.close();
  }, [clinicianId]);

  return { alerts };
}
```

Use in `ClinicianDashboard.tsx`:
```tsx
const { alerts } = useClinicianAlerts();
// Show red banner if alerts.length > 0
```

Payment flow is in `services/payment_service.py`:

**1. Create order (backend)**
```python
# POST /api/v1/payments/create-order
import razorpay
from config import settings

client = razorpay.Client(auth=(settings.RAZORPAY_KEY_ID, settings.RAZORPAY_KEY_SECRET))

def create_order(amount_inr: int, plan: str, tenant_id: str) -> dict:
    order = client.order.create({
        'amount': amount_inr * 100,  # Razorpay uses paise (₹1 = 100 paise)
        'currency': 'INR',
        'receipt': f'saathi_{tenant_id}_{plan}',
        'notes': {'tenant_id': tenant_id, 'plan': plan}
    })
    return order  # order['id'] is sent to frontend
```

**2. Frontend triggers Razorpay checkout**
```tsx
const response = await api.post('/api/v1/payments/create-order', { plan: 'professional' });
const options = {
  key: import.meta.env.VITE_RAZORPAY_KEY_ID,
  amount: response.data.amount,
  order_id: response.data.id,
  handler: async (paymentResponse) => {
    await api.post('/api/v1/payments/verify', paymentResponse);
  }
};
new (window as any).Razorpay(options).open();
```

**3. Verify webhook HMAC (backend)**
```python
# POST /api/v1/payments/verify
import hmac, hashlib

def verify_payment(razorpay_order_id, razorpay_payment_id, razorpay_signature):
    msg = f'{razorpay_order_id}|{razorpay_payment_id}'
    expected = hmac.new(
        settings.RAZORPAY_KEY_SECRET.encode(),
        msg.encode(), hashlib.sha256
    ).hexdigest()
    if not hmac.compare_digest(expected, razorpay_signature):
        raise HTTPException(status_code=400, detail='Invalid payment signature')
    # Update tenant.plan in DB
```

Security note: Always verify HMAC server-side. Never trust client-side payment confirmation alone.

